mapper.update:
UPDATE WH_PRESS
SET IS_POPULAR = #{IS_POPULAR}
WHERE PRS_ID = #{PRS_ID}

mapper.select:
SELECT A.CON_ID, A.CON_BODY, A.CREATED_DATE, A.IS_PINNED, B.PRS_NAME, B.PRS_ID, D.THUMB_URL as image, D.MEDIA_URL, D.MEDIA_TYPE FROM WH_STAR_CONTENT A JOIN WH_PRESS B ON A.PRS_ID = B.PRS_ID JOIN STAR_CONTENT_MEDIA D ON A.CON_ID = D.CON_ID WHERE D.SORT_ORDER = 0
AND B.PRS_COUNTRY = #{country}
ORDER BY A.CREATED_DATE DESC LIMIT #{limit} OFFSET #{offset}

SELECT B.PRS_ID, B.PRS_NAME, B.PRS_COUNTRY,
-- 전체 노출 수 COUNT(*) AS TOTAL_CNT,
-- OS별 노출 수 (정산용) SUM(CASE WHEN A.OS = 'ANDROID' THEN 1 ELSE 0 END) AS ANDROID_CNT, SUM(CASE WHEN A.OS = 'IOS' THEN 1 ELSE 0 END) AS IOS_CNT
FROM WH_AD_LOG A JOIN WH_PRESS B ON A.PRS_ID = B.PRS_ID WHERE A.ACTION = 'IMPRESSION' AND DATE_FORMAT(A.CREATED_DATE, '%Y-%m') = #{targetMonth}
AND B.PRS_COUNTRY = #{country}
GROUP BY B.PRS_ID, B.PRS_NAME, B.PRS_COUNTRY ORDER BY TOTAL_CNT DESC

SELECT PRS_ID, PRS_NAME FROM WH_PRESS WHERE PRS_TYPE = '4' AND PRS_USE_YN = 'Y'
AND PRS_COUNTRY = #{country}
ORDER BY PRS_NAME ASC

mapper.update:
UPDATE ipo_requests 
SET status = #{status} 
WHERE id = #{id}

UPDATE WH_GUEST_COMMENT 
SET STATUS = #{STATUS} -- 'BLIND' 또는 'DELETE'
WHERE CMT_ID = #{cmtId}

mapper.insert:
INSERT INTO WH_GUEST_REPORT (
    TARGET_TYPE, TARGET_ID, REPORTER_DEVICE_ID, REASON, CREATED_DATE
) VALUES (
    'COMMENT', #{cmtId}, #{deviceId}, #{reason}, NOW()
)

INSERT INTO WH_GUEST_BLACKLIST (
    DEVICE_ID, REASON, PRS_ID, CREATED_DATE
) VALUES (
    #{targetDeviceId}, #{reason}, #{prsId}, NOW()
)
ON DUPLICATE KEY UPDATE REASON = #{reason}

INSERT INTO WH_GUEST_BLOCK (DEVICE_ID, REASON, CREATED_DATE)
VALUES (#{deviceId}, #{reason}, NOW())
ON DUPLICATE KEY UPDATE REASON = #{reason}

mapper.select:
SELECT COUNT(DISTINCT A.MEM_ID) FROM WH_AD_LOG A
INNER JOIN WH_PRESS B ON A.PRS_ID = B.PRS_ID AND B.PRS_COUNTRY = #{country}
WHERE A.ACTION = 'IMPRESSION' AND DATE(A.CREATED_DATE) = CURDATE()

SELECT IFNULL(ROUND((COUNT(DISTINCT TODAY.MEM_ID) / NULLIF(COUNT(DISTINCT YESTERDAY.MEM_ID), 0)) * 100), 0) FROM ( SELECT DISTINCT A.MEM_ID FROM WH_AD_LOG A
INNER JOIN WH_PRESS B ON A.PRS_ID = B.PRS_ID AND B.PRS_COUNTRY = #{country}
WHERE A.ACTION = 'IMPRESSION' AND DATE(A.CREATED_DATE) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) ) YESTERDAY LEFT JOIN ( SELECT DISTINCT A.MEM_ID FROM WH_AD_LOG A
INNER JOIN WH_PRESS B ON A.PRS_ID = B.PRS_ID AND B.PRS_COUNTRY = #{country}
WHERE A.ACTION = 'IMPRESSION' AND DATE(A.CREATED_DATE) = CURDATE() ) TODAY ON YESTERDAY.MEM_ID = TODAY.MEM_ID
